# Public event payload (v1). Documented at docs.example.com/api/events.
#
# NOTE: `timestamp` remains an ISO8601 string for v1 compatibility
# (bravo-corp, vectorly depend on this). `timestamp_epoch` is an additive
# field added for northside-co (ticket T-9901) and any consumer that
# prefers unix epoch seconds. A proper type change belongs in a v2 payload.
from datetime import datetime, timezone


def _to_epoch(ts):
    if isinstance(ts, (int, float)):
        return int(ts)
    if isinstance(ts, datetime):
        dt = ts if ts.tzinfo else ts.replace(tzinfo=timezone.utc)
        return int(dt.timestamp())
    # assume ISO8601 string
    s = str(ts).replace("Z", "+00:00")
    dt = datetime.fromisoformat(s)
    if not dt.tzinfo:
        dt = dt.replace(tzinfo=timezone.utc)
    return int(dt.timestamp())


def serialize(event):
    return {
        "id": event.id,
        "type": event.type,
        "timestamp": event.ts,              # ISO8601 string (v1, unchanged)
        "timestamp_epoch": _to_epoch(event.ts),  # unix epoch seconds (additive)
        "data": event.data,
    }

